REQUIRED = {'case_id', 'lint', 'matrix', 'supported', 'tests', 'types'}
REJECT = 'FAIL_CI_GATE'

def assess(record: dict) -> str:
    absent = sorted(REQUIRED - record.keys())
    if absent:
        return "MISSING:" + ",".join(absent)
    contract_ok = record["lint"] and record["types"] and record["tests"] and record["matrix"] == record["supported"]
    return "PASS" if contract_ok else REJECT

valid_fx = {"case_id": 'CASO-PIU-044-1A', **{'lint': True, 'types': True, 'tests': True, 'matrix': {'3.11', '3.12'}, 'supported': {'3.11', '3.12'}}}
